window.SDOC_MAP_MID_TO_NODES = {"1":{"MID":"5c09208f5cc448e3b9e92e7315b85127","UID":"EL-161","TITLE":"Introduction","_LINK":"EL-161"},"2":{"MID":"fa29a5d00c1e4609b24bae1d8677660f","UID":"EL-187","TITLE":"Purpose","_LINK":"EL-187"},"3":{"MID":"57ee511a04864b339d9b0a310cb5fc9d","STATEMENT":"This document describes couple of requirements related to the configuration (administration) portal.\n\n","_LINK":"57ee511a04864b339d9b0a310cb5fc9d"},"4":{"MID":"31cc710ed5e34868b0f22190f4e79e9c","UID":"EL-186","TITLE":"References","_LINK":"EL-186"},"5":{"MID":"cca028baa87840dd8e4f96a6ec33113f","STATEMENT":"Specifications:\n\n- [LINK: f534bf6955ea46e7f18be344ac667] \n\nTesting:\n\n- [LINK: a92a7e7f4a7c4b39c58d79f921d486e8] \n\n\n","_LINK":"cca028baa87840dd8e4f96a6ec33113f"},"6":{"MID":"098b097353c24d4c83579caeb3d2c2e1","UID":"EL-162","TITLE":"Requirements","_LINK":"EL-162"},"7":{"MID":"d3fa944ee2e74104a1633dc20e457091","UID":"EL-163","TITLE":"User Roles","_LINK":"EL-163"},"8":{"MID":"49a75c0dadb8484aa869dcbee61c364a","UID":"EL-165_d1213b973615777a8461526eea2e35a","POLARION_ID":"EL-165","STATUS":"Reviewed","TITLE":"By default there are two roles:","DESCRIPTION":"\n- administrator\n- user\n\n\n","_LINK":"EL-165_d1213b973615777a8461526eea2e35a"},"9":{"MID":"b273706dbf2e45d58216c7a73f9d3cd8","UID":"EL-166_d1213b973615777a8461526eea2e35a","POLARION_ID":"EL-166","STATUS":"Reviewed","TITLE":"User role id conditions:","DESCRIPTION":"\n- may not contain spaces\n- may not contain non-ASCII characters\n\n\n","_LINK":"EL-166_d1213b973615777a8461526eea2e35a"},"10":{"MID":"759627ddc3954efd83ed81b16eabc08f","UID":"EL-164_d1213b973615777a8461526eea2e35a","POLARION_ID":"EL-164","STATUS":"Reviewed","TITLE":"User can be assigned into multiple user roles","COMMENT":"Item was e-signed\n\nApproval verdict:\nDisapproved\n\n","_LINK":"EL-164_d1213b973615777a8461526eea2e35a"},"11":{"MID":"0967d81bf5ff4ec1915034315378f3c2","UID":"EL-124","TITLE":"Introduction","_LINK":"EL-124"},"12":{"MID":"0011c150daa64b258eab8f55eef7b790","STATEMENT":"This document is configured to showcase the\nPDF Export Watermark\nfeature. After selecting\nOperations > Export to PDF,\neach page is watermarked with an image. Rules for document watermarks can also be specified via a plugin. This plugin lets users force watermarks based on a custom field value like \"Restricted documents\".\n\n","_LINK":"0011c150daa64b258eab8f55eef7b790"},"13":{"MID":"20fba23b6dbb4439a0ea143caf349caa","UID":"EL-5","TITLE":"Purpose","_LINK":"EL-5"},"14":{"MID":"1303a8f5ba274da599f33f7e3dde4273","STATEMENT":"A Product Specification is a complete description of the behavior of the product to be developed. It includes a set of User Stories that describe all the interactions that users will have with the software. In addition to User Stories, this document also contains Requirements.\n\n","_LINK":"1303a8f5ba274da599f33f7e3dde4273"},"15":{"MID":"e107a45ab7324b08b35935eec5118fa2","UID":"EL-125","TITLE":"Scope","_LINK":"EL-125"},"16":{"MID":"60e5b6cf890647e8966f9a03aa7e4297","STATEMENT":"The document describes a fictitious online eBook lending library with an optional online eBook sales component. The focus is on simplicity rather than depth and completeness, so that you may more easily understand the Document's features.\nNot all the User Stories need to be implemented in the 1.0 release.  The release planning is managed separately. See \n.\n\n","_LINK":"60e5b6cf890647e8966f9a03aa7e4297"},"17":{"MID":"6986ee027be74b03b3e94afc17e73aa3","UID":"EL-70","TITLE":"References","_LINK":"EL-70"},"18":{"MID":"89669b5fbe7e40d7b30c1a2be0dcebe3","STATEMENT":"Specifications:\n\n- [LINK: d1213b973615777a8461526eea2e35a] \n- Specification Catalog Specification \n\n\n","_LINK":"89669b5fbe7e40d7b30c1a2be0dcebe3"},"19":{"MID":"c563cc3ddbb04b74ba4d6365aaf321f0","UID":"EL-6","TITLE":"Overall Description","_LINK":"EL-6"},"20":{"MID":"1c87c9afed30436aaf4b69183c2ddd65","STATEMENT":"This system provides an online portal analogous to a public library where registered patrons can \"borrow\" books. The main difference being, that the books in the library catalog are all in electronic formats that incorporate Digital Rights Management (DRM). This lets the system “lend” an allowed number of copies to registered users. In addition, when a book has the proper rights, the E-Library can sell patrons a license for a personal copy of the electronic book that they can retain permanently.\n\n","_LINK":"1c87c9afed30436aaf4b69183c2ddd65"},"21":{"MID":"7fd8e91afec44026830d6d17f2fcd926","UID":"EL-7","TITLE":"Abbreviations and Terms","_LINK":"EL-7"},"22":{"MID":"17fea8e15e84468381954d4cbe239998","STATEMENT":"\n.. list-table::\n    :widths: 1 1\n    :header-rows: 1\n\n    * - TERM\n      - DEFINITION\n    * - Cart\n      - i.e. “Shopping Cart” – A collection of one or more eBooks that a patron has marked for purchase during the current session.\n    * - Catalog\n      - The database of eBooks available for loan and possibly for sale.\n    * - Check Out\n      - The act of “borrowing” an eBook from the library. The term is not used in reference to the process of paying for a purchased eBook. (See Purchase.)\n    * - Check In\n      - The act of “returning” a previously “borrowed” (checked out) eBook.\n    * - DRM\n      - Digital Rights Management\n    * - eBook\n      - An electronic book or other publication lent or sold by the E-Library system.\n    * - ISBN\n      - International Standard Book Number\n    * - LC\n      - Library of Congress\n    * - Loan\n      - See Lend.\n    * - Lend\n      - The process of flagging an eBook so the appropriate DRM understands that one of the allowable number of “copies” has been allocated to a patron for the allowable lending period.\n    * - Patron\n      - A user of the E-Library portal.\n    * - Purchase\n      - The process by which library patrons purchase a DRM license for a personal copy of an eBook.(Also refers to the action of a user navigating through the process of purchasing the eBooks listed in their Cart.)\n    * - Store\n      - An area of the portal that lists a subset of the library’s eBooks.(eBooks that users can purchase a personal copy license for.)\n\n","_LINK":"17fea8e15e84468381954d4cbe239998"},"23":{"MID":"a874049664604e57a000bcad47e0a371","UID":"EL-112","TITLE":"Product Backlog","_LINK":"EL-112"},"24":{"MID":"c5a6605b7aa04022809bac001e44e4ae","UID":"EL-110","TITLE":"Basics","_LINK":"EL-110"},"25":{"MID":"bd81e8be7cc745fcb6808a4b3541856c","UID":"EL-198_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-198","STATUS":"In Progress","TITLE":"Basic Product Behavior","DESCRIPTION":"This Epic sums up the basic behavior of the product.\n\n","_LINK":"EL-198_f534bf6955ea46e7f18be344ac667"},"26":{"MID":"75816592cc224ad4ade1802a7366c828","UID":"EL-107_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-107","STATUS":"Verified","TITLE":"User Statistics","DESCRIPTION":"Users should easily access information on what books they have borrowed.\n\n","_LINK":"EL-107_f534bf6955ea46e7f18be344ac667"},"27":{"MID":"5c7b20f3bb1d4224aee4a4c5c42015e1","UID":"EL-191_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-191","STATUS":"Draft","TITLE":"Password Regex","DESCRIPTION":"The password must fit the specified Requirements.\n\n","_LINK":"EL-191_f534bf6955ea46e7f18be344ac667"},"28":{"MID":"95dfe4943aae4b39a273d4fe7d804579","UID":"EL-105_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-105","STATUS":"Verified","TITLE":"Login Page","DESCRIPTION":"When users want to access the Elibrary portal they need to login and provide valid credentials.\n\n","_LINK":"EL-105_f534bf6955ea46e7f18be344ac667"},"29":{"MID":"e1afca4efd264c2abe364fe7b072d94f","UID":"EL-138_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-138","STATUS":"Implemented","TITLE":"Access the list of favorite books","DESCRIPTION":"Users must be able to easily access their list of \"Favorite\" books.\n\n","_LINK":"EL-138_f534bf6955ea46e7f18be344ac667"},"30":{"MID":"ec5825038feb4c4a958d0d8e7131c934","UID":"EL-139_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-139","STATUS":"In Progress","TITLE":"Maintain the list of favorite books","DESCRIPTION":"Users should be able to maintain their list of \"Favorite\" books.\n\n","_LINK":"EL-139_f534bf6955ea46e7f18be344ac667"},"31":{"MID":"0cc1cd624d344ee2bded151fc94c874e","UID":"EL-136_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-136","STATUS":"In Progress","TITLE":"Configure contact information","DESCRIPTION":"Users must be able to configure their contact information.\n\n","_LINK":"EL-136_f534bf6955ea46e7f18be344ac667"},"32":{"MID":"4fed53fafbc84c0b8716d2d5c116fbcc","UID":"EL-137_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-137","STATUS":"Accepted","TITLE":"Mark a book as favorite","DESCRIPTION":"Users must be able to mark a book as a \"Favorite\".\n\n","_LINK":"EL-137_f534bf6955ea46e7f18be344ac667"},"33":{"MID":"32868bf2e18c4a3d826d4e379bfe37e3","UID":"EL-140_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-140","STATUS":"Verified","TITLE":"Administration","DESCRIPTION":"Basic users may not be allowed to administer the elibrary system.\n\n","_LINK":"EL-140_f534bf6955ea46e7f18be344ac667"},"34":{"MID":"12b5b10888464dbd8c007cc28fdac69f","UID":"EL-113","TITLE":"Book Information","_LINK":"EL-113"},"35":{"MID":"fee48efb22114f29b2e6bc974ee2acd0","UID":"EL-199_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-199","STATUS":"In Progress","TITLE":"Books","DESCRIPTION":"This Epic describes the Book object.\n\n","_LINK":"EL-199_f534bf6955ea46e7f18be344ac667"},"36":{"MID":"a66f071a029c485aab8bf955549d5e12","UID":"EL-118_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-118","STATUS":"Verified","TITLE":"Detailed book information","DESCRIPTION":"Users want to view additional information about a book:\n\n- Number of pages\n- Who illustrated the book\n- Price\n\n\n","_LINK":"EL-118_f534bf6955ea46e7f18be344ac667"},"37":{"MID":"3e2e5bf587304c06a33ee30b9be0e643","UID":"EL-116_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-116","STATUS":"Verified","TITLE":"Basic Book Details","DESCRIPTION":"Users want to view basic information about the book:\n\n- Title\n- Author\n- Published date\n- ISBN\n\n\n","_LINK":"EL-116_f534bf6955ea46e7f18be344ac667"},"38":{"MID":"f0496ac4c1504fe5ade33ffce708cb0d","UID":"EL-117_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-117","STATUS":"Accepted","TITLE":"Summary of the book","DESCRIPTION":"When viewing book details, users also want to read a book's summary (abstract).\n\n","_LINK":"EL-117_f534bf6955ea46e7f18be344ac667"},"39":{"MID":"10d4131e187f49988f681449bebe9b1a","UID":"EL-130_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-130","STATUS":"Accepted","TITLE":"Online services","DESCRIPTION":"Users also want to easily get a list of online resources, with links to Amazon, ReviewMyBook and other online services.\nThis list of services needs to be configurable.\n\n","_LINK":"EL-130_f534bf6955ea46e7f18be344ac667"},"40":{"MID":"1f23394bbd80425cac523955a61273fe","UID":"EL-131_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-131","STATUS":"Verified","TITLE":"EBook -  supported readers","DESCRIPTION":"If the book is an eBook, users must be able to get information about the supported reader applications and platforms.\n\n","_LINK":"EL-131_f534bf6955ea46e7f18be344ac667"},"41":{"MID":"090db09faef64403b704be82d20de9a8","UID":"EL-114","TITLE":"Author Information","_LINK":"EL-114"},"42":{"MID":"45d1ac2aa3ce42b6b290734bbfa5738f","UID":"EL-200_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-200","STATUS":"In Progress","TITLE":"Author","DESCRIPTION":"This Epic describes the Author object.\n\n","_LINK":"EL-200_f534bf6955ea46e7f18be344ac667"},"43":{"MID":"1de18fa90a7c4215855f614553651fef","UID":"EL-119_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-119","STATUS":"Verified","TITLE":"Basic Author Details","DESCRIPTION":"When viewing a book's details, users also want to get information about the author or authors. The details should include:\n\n- Full name\n- Date of birth\n- Date of death (If deceased) \n- A list of other books written by them. (If more than 5, the 6th entry can be a link to a complete bibliography page.)\n\n\n","_LINK":"EL-119_f534bf6955ea46e7f18be344ac667"},"44":{"MID":"a8c3a25514384c06ad65885208b4b839","UID":"EL-121_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-121","STATUS":"Accepted","TITLE":"When viewing an author's list of books, users want to see which books are stored...","DESCRIPTION":"When viewing an author's list of books, users want to see which books are stored in the library and whether or not they are currently available for check out.\n\n","_LINK":"EL-121_f534bf6955ea46e7f18be344ac667"},"45":{"MID":"502190c264f44a228c485edb55aea73b","UID":"EL-120_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-120","STATUS":"Reviewed","TITLE":"Photo of an author","DESCRIPTION":"Show photo(s) of an author.\n\n","_LINK":"EL-120_f534bf6955ea46e7f18be344ac667"},"46":{"MID":"836f2fa9ffaf4dabb02b2c33ae220e32","UID":"EL-111","TITLE":"Searches","_LINK":"EL-111"},"47":{"MID":"36aab54da99b4e31a5012545f6ddcd69","UID":"EL-201_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-201","STATUS":"In Progress","TITLE":"Searches","DESCRIPTION":"This Epic describes all relevant information for the Search feature.\n\n","_LINK":"EL-201_f534bf6955ea46e7f18be344ac667"},"48":{"MID":"815efa7b4b4d49188649e3921c3bcb53","UID":"EL-108_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-108","STATUS":"Verified","TITLE":"Search for a book by book name","DESCRIPTION":"Users typicaly search for the book by name. This feature should be accesssible all the times.\n\n","_LINK":"EL-108_f534bf6955ea46e7f18be344ac667"},"49":{"MID":"e25fadd051ff42c0adf5aa2c0610d241","UID":"EL-115_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-115","STATUS":"Verified","TITLE":"Search for an author by author name","DESCRIPTION":"Users want to be able to search for authors by name.\n\n","_LINK":"EL-115_f534bf6955ea46e7f18be344ac667"},"50":{"MID":"43409dad9ccf439f8665ba1b6a891f38","UID":"EL-134_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-134","STATUS":"Verified","TITLE":"Listing of the 20 most frequently borrowed eBooks.","DESCRIPTION":"The system should provide a way to return a list of the 20 most frequently borrowed eBooks.\n\n- The actual number should be configurable by an administrator.\n- The UI should provide a selectable list of values: 10, 20, 25, 50, 100\n\n\n","_LINK":"EL-134_f534bf6955ea46e7f18be344ac667"},"51":{"MID":"19afe27723444516b6e2fcffee3af165","UID":"EL-135_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-135","STATUS":"Verified","TITLE":"The listing of 10-50 recently checked books.","DESCRIPTION":"The system should provide an easy way to get the listing of the 10-50 (configurable) most recently checked-in eBooks.\n\n","_LINK":"EL-135_f534bf6955ea46e7f18be344ac667"},"52":{"MID":"80c6fd618b83438bac103e056f92b528","UID":"EL-132_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-132","STATUS":"Change Implementation","TITLE":"Advanced Search should provide an easy way to construct complex search queries","DESCRIPTION":"Advanced Search \nshould provide an easy way to construct complex search queries based on multiple fields with different logic (e.g. AND, OR, NOT).\n\n","_LINK":"EL-132_f534bf6955ea46e7f18be344ac667"},"53":{"MID":"bd22d15b51a24451b609046308efc61c","UID":"EL-133_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-133","STATUS":"Verified","TITLE":"List of newly added books.","DESCRIPTION":"The system must provide an easy way to list newly added books. It can return a listing of the 10 - 50 (configurable) most recently added eBooks.\n\n","_LINK":"EL-133_f534bf6955ea46e7f18be344ac667"},"54":{"MID":"7fb5774f34e8417bbcf408e494d278a2","UID":"EL-122_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-122","STATUS":"In Progress","TITLE":"Users like to also search for content - (Full-text search)","DESCRIPTION":"Users aslo like to search for content. This requires a full-text search option.\n\n","_LINK":"EL-122_f534bf6955ea46e7f18be344ac667"},"55":{"MID":"ecd2f705f11649cc8a0436fa6b8343c6","UID":"EL-109_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-109","STATUS":"In Progress","TITLE":"Search for a book by advanced properties","DESCRIPTION":"Users want to search for books using additional properties, for example ISBN or date, but this advanced search should not be too complicated.\n\n","_LINK":"EL-109_f534bf6955ea46e7f18be344ac667"},"56":{"MID":"5687f9a71a8d4970896cc69a25ca0336","UID":"EL-127","TITLE":"Administration","_LINK":"EL-127"},"57":{"MID":"4d84a663b68046bda3eeee20219262cc","UID":"EL-141","TITLE":"User Roles","_LINK":"EL-141"},"58":{"MID":"c9f5a391c73447b79bf93126db4139f7","STATEMENT":"The system must provide for the following types of user accounts:\n\n.. list-table::\n    :widths: 1 1\n    :header-rows: 1\n\n    * - ACCOUNT TYPE\n      - PERMISSIONS\n    * - Administrator\n      - Can access any component or area of the system including the accounts of other users.\n    * - Librarian\n      - Can access the catalog management features of the system.\n    * - Patron\n      - Can access the general library features, including browsing, searching, check out, check in, reserve, and purchase.\n    * - Student\n      - Same as a Patron, except students can not access Purchase features.\n\n","_LINK":"c9f5a391c73447b79bf93126db4139f7"},"59":{"MID":"84218a3372da498e9c65836c7fb319e2","UID":"EL-202_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-202","STATUS":"Verified","TITLE":"User Roles","DESCRIPTION":"This Epic sums up all the information on the User Roles feature.\n\n","_LINK":"EL-202_f534bf6955ea46e7f18be344ac667"},"60":{"MID":"5de579fe483e461dbf79086e748e3e48","UID":"EL-143_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-143","STATUS":"Verified","TITLE":"System Administrator must be able to set the user roles.","_LINK":"EL-143_f534bf6955ea46e7f18be344ac667"},"61":{"MID":"ff7ae66cc5df4c5ab63ab00a8be8881e","UID":"EL-142_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-142","STATUS":"Verified","TITLE":"There are two user roles: Basic User and Administrator.","DESCRIPTION":"There are two user roles: Basic User and Administrator. Basic users have no access to the administration portal.\n\n","_LINK":"EL-142_f534bf6955ea46e7f18be344ac667"},"62":{"MID":"a15d50aa991d458b9f4e3b8a2e2f23e0","UID":"EL-8","TITLE":"Requirements","_LINK":"EL-8"},"63":{"MID":"916453ffcc2d401a81ec72afd87491d8","UID":"EL-9","TITLE":"Performance Requirements","_LINK":"EL-9"},"64":{"MID":"6351daec9ad6468b8cc0e56aa57ab35e","STATEMENT":"If there are performance requirements for the product under various circumstances, state them here and explain their rationale.This helps developers understand the intended performance targets and make design choices accordingly. Specify the timing relationships for real time systems. Make these requirements as specific as possible. You may need to state performance requirements for individual functional requirements or features.\n\n","_LINK":"6351daec9ad6468b8cc0e56aa57ab35e"},"65":{"MID":"3752026293014781964ec78e92a0c17f","UID":"EL-69_f534bf6955ea46e7f18be344ac667","POLARION_ID":"EL-69","STATUS":"Rejected","TITLE":"This is a sample of non functional requirement.","_LINK":"EL-69_f534bf6955ea46e7f18be344ac667"},"66":{"MID":"f00ea1ce66b042dd98794b2287d0c2dd","UID":"EL-10","TITLE":"Safety Requirements","_LINK":"EL-10"},"67":{"MID":"60bd703f15cf4f9589c7b1724b6c033a","STATEMENT":"Specify any requirements concerned with possible loss, damage, or harm that could result from the use of the product. Define any safeguards or actions that must be taken, as well as actions that must be prevented. Refer to any external policies or regulations that describe safety issues that could affect the product’s design or use. Define any safety certifications that must be satisfied.\n\n","_LINK":"60bd703f15cf4f9589c7b1724b6c033a"},"68":{"MID":"1d17b73ad14941e0a4fcbb0a190159e5","UID":"EL-11","TITLE":"Security Requirements","_LINK":"EL-11"},"69":{"MID":"d6946e06c30549bbb4fdcaa4dc72557f","STATEMENT":"Specify any requirements regarding security or privacy issues surrounding the use of the product or the protection of data used and created by the product. Define any user identity authentication requirements. Refer to any external policies or regulations containing security issues that affect the product. Define any security or privacy certifications that must be satisfied.\n\n","_LINK":"d6946e06c30549bbb4fdcaa4dc72557f"},"70":{"MID":"298371441b734f84a1cb00023b9dbb31","UID":"EL-12","TITLE":"Software Quality Attributes","_LINK":"EL-12"},"71":{"MID":"0aab68833fb341229e412e026964140c","STATEMENT":"Specify any additional quality characteristics for the product that will be important to either customers or developers. Some to consider are: adaptability, availability, correctness, flexibility, interoperability, maintainability, portability, reliability, reusability, robustness, testability, and usability. Write these to be specific, quantitative, and verifiable when possible. At the very least, clarify the relative preferences for various attributes, such as ease of use over ease of learning.\n\n","_LINK":"0aab68833fb341229e412e026964140c"},"72":{"MID":"76e66b68f51441349f3471a7ec758949","UID":"EL-13","TITLE":"Other Requirements","_LINK":"EL-13"},"73":{"MID":"62011106c2b145b0943609f13c1c2f0c","STATEMENT":"Define any other requirements not covered elsewhere in the specification. This might include database requirements, internationalization requirements, legal requirements, reuse objectives for the project, and so on. Add any new sections that are pertinent to the project.\n\n","_LINK":"62011106c2b145b0943609f13c1c2f0c"},"74":{"MID":"0fbd2ffd581147a49643f7d328f26ad9","UID":"EL-128","TITLE":"Appendix A: Terminology/Glossary/Definitions list","_LINK":"EL-128"},"75":{"MID":"5f1741f8d150452aa8e2bbfd2c944895","STATEMENT":"Define all the terms necessary to properly interpret this document, including acronyms and abbreviations. You may wish to build a separate glossary that spans multiple projects or the entire organization, and just include terms specific to a single project in each document.\n\n","_LINK":"5f1741f8d150452aa8e2bbfd2c944895"},"76":{"MID":"7c2b9ff1e8af4f3a92bca3e1ecfd0fbd","UID":"EL-15","TITLE":"Appendix B: Analysis Models","_LINK":"EL-15"},"77":{"MID":"89fbd72b14b8463585bd075f0ea0d04f","STATEMENT":"Optionally, include any pertinent analysis models, such as data flow diagrams, class diagrams, state-transition diagrams, or entity-relationship diagrams.\n\n","_LINK":"89fbd72b14b8463585bd075f0ea0d04f"},"78":{"MID":"ab866f61111e4d74b5b8ff850f259f05","UID":"EL-29","TITLE":"Introduction","_LINK":"EL-29"},"79":{"MID":"5819b7b3f02b4cecb89ef70dd5911281","UID":"EL-30","TITLE":"Purpose","_LINK":"EL-30"},"80":{"MID":"a906a4409f314076b2151ce8570e4cc1","STATEMENT":"Test Case Specification collects the test cases. Each test case specifies inputs, predicted results, and a set of execution conditions for a test item.\n\n","_LINK":"a906a4409f314076b2151ce8570e4cc1"},"81":{"MID":"9829c73257234b298417afc8b56baced","UID":"EL-31","TITLE":"Scope","_LINK":"EL-31"},"82":{"MID":"db13038318fa4d1f8c5af757ed88f6ca","STATEMENT":"Provide a short description of the software features being tested.\n\n","_LINK":"db13038318fa4d1f8c5af757ed88f6ca"},"83":{"MID":"bed3cc8276ca47e987a608ff29ff9ae9","UID":"EL-32","TITLE":"References","_LINK":"EL-32"},"84":{"MID":"a0c28c40198f4919801f903e55df0602","STATEMENT":"Specifications:\n\n- [LINK: d1213b973615777a8461526eea2e35a] \n- Specification Catalog Specification \n- [LINK: f534bf6955ea46e7f18be344ac667] \n\n\n","_LINK":"a0c28c40198f4919801f903e55df0602"},"85":{"MID":"59952ced26ba48aebc062834e9b890b8","UID":"EL-34","TITLE":"Test Cases","_LINK":"EL-34"},"86":{"MID":"691fc94712ae4f82a0219442d4b24166","UID":"EL-71","TITLE":"Catalog Test Cases","_LINK":"EL-71"},"87":{"MID":"dd0a4c759ff044dea8b90ac3a62077a6","UID":"EL-41_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-41","STATUS":"Active","TITLE":"Rich text book summary","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Search for a book. \n      - E.g. using keywords\n      - The results page is shown. \n    * - Open a book's properties dialog.\n      - \n      - The book's properties dialog is shown.\n    * - Check for the \"Summary\" field.\n      - \n      - A \"Summary\" field is displayed in the dialog and it should contain some rich text.\n\n","_LINK":"EL-41_a92a7e7f4a7c4b39c58d79f921d486e8"},"88":{"MID":"b581d51e49f44a87982a70014c3c77d1","UID":"EL-40_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-40","STATUS":"Active","TITLE":"Open Book Properties","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Search for a book.\n      - E.g. using keywords\n      - The results page is shown.\n    * - Double click on a book.\n      - \n      - The book's properties dialog is shown.\n    * - Hit the \"Enter\" key.\n      - \n      - Results are shown and the keyword is highlighted. The dialog renders nicely: name, ISBN, author, data, ..\n\n","_LINK":"EL-40_a92a7e7f4a7c4b39c58d79f921d486e8"},"89":{"MID":"ba4d77cc4e964af1a65f454413930e6e","UID":"EL-39_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-39","STATUS":"Active","TITLE":"Search for book using keywords","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Open \"Search perspective\".\n      - Login to the E-Library Portal, and click search in the top left corner.\n      - The Search page is displayed. The focus should, by default, be in the \"Search\" text field.\n    * - Type: dog.\n      - \n      - dog is typed in the \"Search\" text field.\n    * - Hit the \"Enter\" key.\n      - \n      - Results are shown and keyword is highlighted.\n\n","_LINK":"EL-39_a92a7e7f4a7c4b39c58d79f921d486e8"},"90":{"MID":"f35cc411751343e5a6c2d1e2997475d7","UID":"EL-38_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-38","STATUS":"Active","TITLE":"Search for book using ISBN","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Open \"Search perspective\".\n      - Login to the E-Library Portal, and click \"Search\" in the top left corner.\n      - The Search page is displayed.\n    * - Select \"Search by ISBN\".\n      - \n      - There is a search via drop-down list next to the search field.\n    * - Type: 12-34-567.\n      - \n      - The ISBN field should be validated, so you cannot click search before you enter the full number.\n    * - Click \"Search\".\n      - \n      - Results are shown, 1 book should be returned.\n\n","_LINK":"EL-38_a92a7e7f4a7c4b39c58d79f921d486e8"},"91":{"MID":"12a74914885d4a8eaf1d7d873811b0c9","UID":"EL-37_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-37","STATUS":"Active","TITLE":"Open E-Library portal","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Login to the E-Library portal.\n      - \n      - On login the E-library portal is opened.\n    * - Scroll down the home page.\n      - \n      - Search, add and administration portlets are rendered correctly.\n\n","_LINK":"EL-37_a92a7e7f4a7c4b39c58d79f921d486e8"},"92":{"MID":"271030af2cf048e487daebdda05c1d37","UID":"EL-36_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-36","STATUS":"Active","TITLE":"Login to the portal","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Open Login Screen.\n      - Go to the E-Library Portal welcome page and click login on the right hand corner. \n      - Login screen with user name and password text fields is displayed.\n    * - Enter incorrect User Details.\n      - Incorrect details: admin/wrong\n      - The login button is disabled until both user name and password is entered.\n    * - Click \"Login\".\n      - \n      - Login failed message is shown.\n\n","_LINK":"EL-36_a92a7e7f4a7c4b39c58d79f921d486e8"},"93":{"MID":"be0985296fba4c07bd2b685a793b9c93","UID":"EL-43_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-43","STATUS":"Active","TITLE":"Favorite Books","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Open the portal view.\n      - Login to the E-Library Portal. \n      - Portal view is opened and different portlets are rendered there.\n    * - Check \"Top 10 favorite books\"\n      - The portal view page shoud display the \"Top 10 favorite books\" portlet by default.\n      - The portlet is displayed and it 10 books are listed.\n\n","_LINK":"EL-43_a92a7e7f4a7c4b39c58d79f921d486e8"},"94":{"MID":"ea06cbc0fec54821a0e61362fb84763b","UID":"EL-42_a92a7e7f4a7c4b39c58d79f921d486e8","POLARION_ID":"EL-42","STATUS":"Active","TITLE":"Open Author details","DESCRIPTION":"\n.. list-table::\n    :widths: 1 1 1\n    :header-rows: 1\n\n    * - Search for a book. \n      - E.g. using keywords\n      - The results page is shown. \n    * - Open a book's properties dialog. \n      - \n      - The book's properties dialog is shown. \n    * - Check the author's name.\n      - The book's \"Properties\" dialog should show the book's author.\n      - The author's name is displayed in the dialog and is clickable.\n    * - Click on the author's name.\n      - Left click to open the \"Author's Details\" dialog.\n      - The dialog is opened and renders: First name, last name, nationality, and date of birth .\n\n","_LINK":"EL-42_a92a7e7f4a7c4b39c58d79f921d486e8"},"95":{"MID":"d0c4a88d9f984ac69b7eed6d336ea680","UID":"EL-35","TITLE":"Appendix A: Terminology/Glossary/Definitions list","_LINK":"EL-35"},"96":{"MID":"4eecb739eb3b44ec8c8e7ddaaf163bf4","STATEMENT":"Define all the terms necessary to properly interpret this document, including acronyms and abbreviations. You may wish to build a separate glossary that spans multiple projects or the entire organization, and just include terms specific to a single project in each document.\n\n","_LINK":"4eecb739eb3b44ec8c8e7ddaaf163bf4"}};
